/**
 * @summary List assets in a project
 */
export const getListAssetsUrl = (
  projectId: number,
  params?: ListAssetsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/projects/${projectId}/assets?${stringifiedParams}`
    : `/api/projects/${projectId}/assets`;
};

export const listAssets = async (
  projectId: number,
  params?: ListAssetsParams,
  options?: RequestInit,
): Promise<Asset[]> => {
  return customFetch<Asset[]>(getListAssetsUrl(projectId, params), {
    ...options,
    method: "GET",
  });
};

export const getListAssetsQueryKey = (
  projectId: number,
  params?: ListAssetsParams,
) => {
  return [
    `/api/projects/${projectId}/assets`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListAssetsQueryOptions = <
  TData = Awaited<ReturnType<typeof listAssets>>,
  TError = ErrorType<unknown>,
>(
  projectId: number,
  params?: ListAssetsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listAssets>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListAssetsQueryKey(projectId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listAssets>>> = ({
    signal,
  }) => listAssets(projectId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!projectId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listAssets>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListAssetsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listAssets>>
>;
export type ListAssetsQueryError = ErrorType<unknown>;

